using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 Cosmos breaking changes:
        // 1. Discriminator property renamed from "Discriminator" to "$type" — preserve old name for existing documents
        // 2. id format changed from "Blog|1" to just "1" — preserve old compound format
        // 3. HasIndex now throws for Cosmos entities — removed (manage indexing via Azure Portal/Bicep)
        modelBuilder.Entity<Blog>(b =>
        {
            b.HasDiscriminator<string>("Discriminator");
            b.HasRootDiscriminatorInJsonId(true);
        });
    }
}

